VALUES
  ('social-worker-moex-05930', 'social-worker', 'social-worker-moex-105-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '訓練成效評估可區分為反應、學習、工作行為、組織改變等四個層次，其中，工作行為層次主要含意是指：', '["想法或感受", "知識與技能的學習吸收", "對本身的工作有所改善", "組織成員的行為改變"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "9e4d5d193ead", "answer_pdf_sha1": "c3d41c596c6d", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05931', 'social-worker', 'social-worker-moex-105-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '非營利組織為了員工發展，在薪資及職位制度設計上為了揚棄單一生涯階梯（single career ladder），而採 取「雙元生涯階梯（dual career ladder）」之設計，下列那一項是較符合這樣的設計之陳述？', '["由社工員可升為督導，督導再升為主管，具職位及薪資之雙元發展", "職位發展與薪水之發展應互相符合相對提高，具雙元對應", "應重視專業中的貢獻，優秀者應提拔擔任主管或負起行政責任，以發展其雙元生涯", "職位高但未必薪水高，因為專業經驗、年資效果及專業貢獻之報酬，因任務而有所不同"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "9e4d5d193ead", "answer_pdf_sha1": "c3d41c596c6d", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05932', 'social-worker', 'social-worker-moex-105-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在工作分析的過程中，機構想要設定擔任某一職位者，應具備的資格、條件或能力的產出。上述內容與 下列那一個名詞較相符？', '["工作說明書", "工作規範", "工作設計單", "工作分析"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "9e4d5d193ead", "answer_pdf_sha1": "c3d41c596c6d", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05933', 'social-worker', 'social-worker-moex-105-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '「夥伴關係」產生的背景是希望提供更具有效能的服務。下列所述有關社會服務領域夥伴關係的共同特 性，何者錯誤？', '["自願性的結合", "互信、互賴、互惠", "階段性的關係", "效能可以增值"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "9e4d5d193ead", "answer_pdf_sha1": "c3d41c596c6d", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05934', 'social-worker', 'social-worker-moex-105-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '員工的在職訓練（in-service training）可分為職場內訓練（on-the-job training）及職場外訓練（off-the-job training），下列那一個訓練屬於職場外訓練？', '["工作輪調（job rotation）", "行為示範（behavior modeling）", "教練法（coaching）", "數位學習（e-learning）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "9e4d5d193ead", "answer_pdf_sha1": "c3d41c596c6d", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05935', 'social-worker', 'social-worker-moex-105-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '某一社福機構為了新進社工員（新手）安排學習養成，讓新進社工員由經驗豐富老手帶領，成為他們的 導師（mentor），在專業、技巧、心理調適、角色上得到全方位帶領。這種職場內訓練方式，可以稱做：', '["體驗式學習（experiential learning）", "角色扮演（role play）", "師徒制（apprenticeship）", "教練法（coaching）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "9e4d5d193ead", "answer_pdf_sha1": "c3d41c596c6d", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05936', 'social-worker', 'social-worker-moex-105-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '人力資源管理（HRM）相對於人事管理（PM），其主要不同在於：', '["重視各種資源管理", "考核員工績效及表現", "把員工當作投資財來發展", "依明文規章來管理員工"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "9e4d5d193ead", "answer_pdf_sha1": "c3d41c596c6d", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05937', 'social-worker', 'social-worker-moex-105-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '社工員時常面臨工作負荷，以及案主問題複雜之挑戰，有效的時間管理可視為解決方法之一。時間管理 須注意的事項中，下列那一項不包含在內？', '["設定個人的目標", "仔細規劃時間", "決定優先次序", "適時獎勵自己"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "9e4d5d193ead", "answer_pdf_sha1": "c3d41c596c6d", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05938', 'social-worker', 'social-worker-moex-105-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在市場定位與行銷組合中，社會工作行銷由過去「4Ps」走向「5Ps」之模式，Doherty 與 Horne（2002） 認為第5個P在社會工作行銷上，指的是：', '["人們（people）", "過程（process）", "計畫（plan）", "套裝服務（package）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "9e4d5d193ead", "answer_pdf_sha1": "c3d41c596c6d", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05939', 'social-worker', 'social-worker-moex-105-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '社會服務機構想要提升品質，可以從提升品質訴求開始。下列有關提升品質的措施，何者錯誤？', '["營造品質文化為典範", "投入資源以追求服務品質", "設計服務供給的品質標準", "鼓勵消費者吸收品質相關知能"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "9e4d5d193ead", "answer_pdf_sha1": "c3d41c596c6d", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
